VALUES
  ('bookkeeper-moex-00279', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', 'A公司111年1月向我國居住者個人甲承租房屋供倉庫之用，每月給付租金20萬元，押金40萬元， 租期2年，嗣甲經稽徵機關依所得稅法規定核定該屋111年度當地一般標準租金300萬元，下列敘述 何者錯誤？', '["A公司每月給付甲之租金淨額為租金減除扣繳稅款後之餘額18萬元", "A公司111年度得列報租金支出300萬元", "甲收取之押金應按郵政儲金一年期定期儲金固定利率計算租賃收入", "甲經稽徵機關調整之標準租金部分，得減除必要損耗及費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00280', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', 'A公司適用勞動基準法並依勞工退休金條例提繳勞工退休金，該公司111年給付員工薪資總額180萬 元，提繳退休金10.8萬元，2名員工自願從各自薪資60萬元中提繳退休金2萬元，下列敘述何者錯誤？', '["A公司111年度可認列退休金費用為10.8萬元", "2名員工自願提繳2萬元退休金，不計入薪資收入課稅", "A公司申報該2名自願提繳員工111年度薪資所得扣繳憑單時，不包括其自願提繳退休金2萬元", "2名員工退休時領取原自願提繳之退休金，免併入計算退職所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00281', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關執行業務者課稅規定，何者錯誤？', '["營利事業給付會計師辦理所得稅申報簽證所給付之公費收入，應辦理扣繳申報", "律師代理訴訟案件取得之勞務報酬，非屬營業稅課稅範圍", "藥師親自主持之藥局經營藥品調劑及兼營銷售藥品業務之收入，應計算執行業務所得課徵綜合所得稅", "中醫診所僅提供醫療勞務者，免辦理營業稅稅籍登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00282', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', 'A公司給付員工薪資所得，扣繳義務人已依規定扣繳稅款，惟未依規定期限按實填報扣繳憑單，依所 得稅法及稅捐稽徵法規定，何者錯誤？', '["經稽徵機關查獲者，應依所得稅法規定裁處罰鍰", "扣繳義務人已自動按實填報扣繳憑單，且屬未經檢舉、未經稅捐稽徵機關或財政部指定之調查人員 進行調查之案件，得依稅捐稽徵法規定，免除行為罰", "扣繳義務人逾規定期限繳納所扣稅款者，應依稅捐稽徵法規定加徵滯納金", "經稽徵機關查獲扣繳義務人侵占已扣繳稅款者，應依稅捐稽徵法規定，處以刑罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00283', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國營利事業持有中華民國境外A公司、B公司及C公司（均為100%持有股份），該3家公司所在國家 之營利事業所得稅率分別為12%、15%、18%，依所得稅法第43條之3規定，何者位於低稅負國家？', '["A", "A及B", "A、B、C均是", "A、B、C均非"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00284', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關國外影片事業在中華民國境內出租影片之所得課稅規定，何者正確？', '["國外影片事業在中華民國境內無分支機構，經由營業代理人出租影片之收入，得向財政部申請核准 以收入之1/2為在中華民國境內之營利事業所得額", "國外影片事業出租影片之所得，無論該事業在中華民國境內有無分支機構，均屬應扣繳之所得", "國外影片事業在中華民國境內設有分支機構者，得按片租收入45%計算出租影片之成本", "在中華民國境內無分支機構之國外影片事業，其出租影片之所得扣繳申報，由營業代理人之負責人 為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00285', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關信託課稅規定，何者錯誤？', '["委託人為營利事業之他益信託契約，受益人享有信託利益之權利價值應於信託成立年度依規定課徵所 得稅", "信託契約之受益人不特定或尚未存在者，信託財產發生之收入，委託人應於所得發生年度計算所得申 報納稅", "因遺囑成立之信託，於遺囑人死亡時，其信託財產應依法課徵遺產稅", "受託人因公益信託而標售或義賣之貨物與舉辦之義演收入，全部供作該公益事業之用者，免徵營業稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00286', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國國民甲110年1月1日以其境內財產成立以其子女乙為受益人之信託契約，乙取得美國國籍', '["111年6月30日銀行給付存款利息100萬元，已扣 繳稅款10萬元", "112年6月30日出售適用房地合一稅制房屋、土地，獲利200萬元，受託人 於113年將信託利益給付予乙，依所得稅法有關信託所得課稅規定，下列敘述何者正確？", "乙應將享有信託利益之權利價值，併入110年度之所得額，自行辦理申報納稅", "受託人應於給付乙利益時，以信託財產運用之收入計算所得，向稽徵機關列單申報113年度所得憑單"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00287', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '美國A公司在我國境內無固定營業場所及營業代理人，其與我國B公司簽訂技術合約，A公司指派 居住於美國之員工甲於112年3月1日出差至我國為B公司提供技術服務，甲於出差期間取得A公 司給付之薪資200萬元，B公司並給付A公司技術服務報酬300萬元，甲於同年4月30日返回美 國，下列敘述何者正確？', '["甲應在離境前就取得A公司之薪資向國稅局辦理申報納稅", "B公司應就給付A公司之技術服務報酬300萬元辦理扣繳申報", "A公司應就取得之技術服務報酬300萬元，委託我國境內營利事業向國稅局辦理申報納稅", "B公司應就甲取得之薪資200萬元辦理扣繳申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00288', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國居住者個人甲112年取得收入如下：①薪資收入200萬元  ②統一發票中獎獎金1千萬元  ③借', '["檢舉賄選取得法務部獎金10萬元  ⑤A銀行給付存款利息12萬元 ⑥出售適用房地合一稅制之房屋、土地之利得250萬元  ⑦取得美國債券利息20萬元。依所得稅法 規定，112年度綜合所得總額及儲蓄投資特別扣除額金額各為何？", "196.3萬元、17萬元", "227萬元、17萬元", "196.3萬元、12萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
